  ('locality-6e11b43e-moex-00093', 'locality-6e11b43e', 'locality-6e11b43e-moex-113-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '下列何者為行政程序法明定之一般法律原則？', '["當事人有利及不利之情形應一律注意", "效能原則", "平等互惠原則", "罪刑法定原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('locality-6e11b43e-moex-00094', 'locality-6e11b43e', 'locality-6e11b43e-moex-113-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '依司法院大法官解釋意旨，下列爭議何者非由行政法院審理？', '["受刑人對於監獄之處分或其他管理措施，認為逾越必要範圍", "人民與行政機關就公有財產出租之履約爭議", "人民依國有林地濫墾地補辦清理規定向行政機關申請訂立租約遭拒", "衛生福利部中央健康保險署與健保特約醫事服務機構就辦理全民健保事項發生履約爭議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('locality-6e11b43e-moex-00095', 'locality-6e11b43e', 'locality-6e11b43e-moex-113-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '關於地方自治與地方制度之敘述，下列何者正確？', '["直轄市、縣（市）、鄉（鎮、市）乃地方制度法所規定之地方自治團體", "地方自治係依據憲法第108條第1項第1款規定之省縣自治通則建構", "省政府並未裁撤，依據憲法本文規定，仍具有地方自治團體地位", "憲法規定直轄市之自治，以法律定之，故立法機關得以法律完全剝奪直轄市之自治"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('locality-6e11b43e-moex-00096', 'locality-6e11b43e', 'locality-6e11b43e-moex-113-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '依中央行政機關組織基準法規定，下列何者非屬行政機關？', '["衛生福利部少子女化對策辦公室", "國防部軍備局", "勞動部勞動力發展署", "行政院主計總處"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('locality-6e11b43e-moex-00097', 'locality-6e11b43e', 'locality-6e11b43e-moex-113-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '關於行政機關管轄之敘述，下列何者錯誤？', '["行政機關之管轄，必須依法規，當事人不得協議變更", "數機關對同一事件均有管轄權時，無論受理該事件之先後次序，皆應尊重機關間之協議，以決 定管轄權歸屬", "職務協助未變更或移轉事件之管轄權", "無隸屬關係之機關，彼此間管轄權之變動，稱之為委託"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('locality-6e11b43e-moex-00098', 'locality-6e11b43e', 'locality-6e11b43e-moex-113-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '下列何者為公務員服務法之適用對象？', '["公立醫院約聘僱醫師", "台灣電力股份有限公司董事長", "公立學校未兼任行政職務教師", "直轄市議會議長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('locality-6e11b43e-moex-00099', 'locality-6e11b43e', 'locality-6e11b43e-moex-113-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '關於行政訴訟之訴訟費用，下列敘述何者錯誤？', '["一般訴訟程序之上訴，徵收新臺幣6,000元之裁判費", "通常訴訟程序及都市計畫審查程序事件之上訴審律師酬金，經法院裁定得列為訴訟費用", "對於上訴審判決提起再審，再審裁判費與上訴裁判費相同", "發回更審後再行上訴，其上訴裁判費減半徵收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('locality-6e11b43e-moex-00100', 'locality-6e11b43e', 'locality-6e11b43e-moex-113-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '關於公務員法律責任之敘述，下列何者錯誤？', '["公務員懲戒案件現已從公務員懲戒委員會改制為懲戒法院所審理", "公務員執行職務所涉及之損害賠償責任僅得依據民法規定處理", "依據刑法規定公務員若犯準職務罪時將會加重其刑罰", "依據公務員懲戒法之規定，對於受懲戒之公務員得科以罰款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL)
